import React, { useState, useEffect } from 'react';
import {
  Dialog,
  DialogTitle,
  DialogContent,
  DialogActions,
  Button,
  TextField,
  Box,
  Typography,
  Divider,
  Alert,
  CircularProgress,
  IconButton,
  InputAdornment,
  Grid,
  Card,
  CardContent,
  Chip
} from '@mui/material';
import {
  Close,
  Visibility,
  VisibilityOff,
  Person,
  Api,
  Save,
  Check
} from '@mui/icons-material';
import { toast } from 'react-toastify';
import authService from '../../services/authService';

const Profile = ({ open, onClose, user, onUserUpdate }) => {
  const [loading, setLoading] = useState(false);
  const [showApiKey, setShowApiKey] = useState(false);
  const [showSecretKey, setShowSecretKey] = useState(false);
  const [showPassphrase, setShowPassphrase] = useState(false);
  const [formData, setFormData] = useState({
    username: '',
    email: '',
    api_key: '',
    secret_key: '',
    passphrase: ''
  });
  const [errors, setErrors] = useState({});

  useEffect(() => {
    if (user && open) {
      setFormData({
        username: user.username || '',
        email: user.email || '',
        api_key: user.api_key || '',
        secret_key: user.secret_key || '',
        passphrase: user.passphrase || ''
      });
      setErrors({});
    }
  }, [user, open]);

  const handleInputChange = (field) => (event) => {
    setFormData(prev => ({
      ...prev,
      [field]: event.target.value
    }));

    // Limpar erro do campo quando o usuário começar a digitar
    if (errors[field]) {
      setErrors(prev => ({
        ...prev,
        [field]: ''
      }));
    }
  };

  const validateForm = () => {
    const newErrors = {};

    if (!formData.username.trim()) {
      newErrors.username = 'Nome de usuário é obrigatório';
    }

    if (!formData.email.trim()) {
      newErrors.email = 'Email é obrigatório';
    } else if (!/\S+@\S+\.\S+/.test(formData.email)) {
      newErrors.email = 'Email inválido';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSave = async () => {
    if (!validateForm()) {
      return;
    }

    try {
      setLoading(true);

      const updateData = {
        username: formData.username,
        email: formData.email
      };

      // Adicionar dados da API apenas se foram preenchidos
      if (formData.api_key.trim()) {
        updateData.api_key = formData.api_key;
      }
      if (formData.secret_key.trim()) {
        updateData.secret_key = formData.secret_key;
      }
      if (formData.passphrase.trim()) {
        updateData.passphrase = formData.passphrase;
      }

      const updatedUser = await authService.updateProfile(updateData);

      if (onUserUpdate) {
        onUserUpdate(updatedUser);
      }

      toast.success('Perfil atualizado com sucesso!');
      onClose();
    } catch (error) {
      console.error('Erro ao atualizar perfil:', error);
      toast.error(error.message || 'Erro ao atualizar perfil');
    } finally {
      setLoading(false);
    }
  };

  const handleClose = () => {
    if (!loading) {
      onClose();
    }
  };

  const isApiConfigured = formData.api_key && formData.secret_key && formData.passphrase;

  return (
    <Dialog
      open={open}
      onClose={handleClose}
      maxWidth="md"
      fullWidth
      PaperProps={{
        sx: { borderRadius: 2 }
      }}
    >
      <DialogTitle sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', pb: 1 }}>
        <Box sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
          <Person color="primary" />
          <Typography variant="h6">Perfil do Usuário</Typography>
        </Box>
        <IconButton onClick={handleClose} disabled={loading}>
          <Close />
        </IconButton>
      </DialogTitle>

      <DialogContent dividers>
        <Box sx={{ py: 1 }}>
          {/* Informações Pessoais */}
          <Card sx={{ mb: 3 }}>
            <CardContent>
              <Typography variant="h6" gutterBottom sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                <Person color="primary" />
                Informações Pessoais
              </Typography>

              <Grid container spacing={2}>
                <Grid item xs={12} sm={6}>
                  <TextField
                    fullWidth
                    label="Nome de Usuário"
                    value={formData.username}
                    onChange={handleInputChange('username')}
                    error={!!errors.username}
                    helperText={errors.username}
                    disabled={loading}
                  />
                </Grid>
                <Grid item xs={12} sm={6}>
                  <TextField
                    fullWidth
                    label="Email"
                    type="email"
                    value={formData.email}
                    onChange={handleInputChange('email')}
                    error={!!errors.email}
                    helperText={errors.email}
                    disabled={loading}
                  />
                </Grid>
              </Grid>
            </CardContent>
          </Card>

          {/* Configurações da API Bitget */}
          <Card>
            <CardContent>
              <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'space-between', mb: 2 }}>
                <Typography variant="h6" sx={{ display: 'flex', alignItems: 'center', gap: 1 }}>
                  <Api color="primary" />
                  API Bitget
                </Typography>
                {isApiConfigured && (
                  <Chip
                    icon={<Check />}
                    label="Configurada"
                    color="success"
                    size="small"
                  />
                )}
              </Box>

              <Alert severity="info" sx={{ mb: 2 }}>
                Configure suas credenciais da API Bitget para sincronizar automaticamente suas operações e saldo.
              </Alert>

              <Grid container spacing={2}>
                <Grid item xs={12}>
                  <TextField
                    fullWidth
                    label="API Key"
                    value={formData.api_key}
                    onChange={handleInputChange('api_key')}
                    type={showApiKey ? 'text' : 'password'}
                    disabled={loading}
                    InputProps={{
                      endAdornment: (
                        <InputAdornment position="end">
                          <IconButton
                            onClick={() => setShowApiKey(!showApiKey)}
                            edge="end"
                          >
                            {showApiKey ? <VisibilityOff /> : <Visibility />}
                          </IconButton>
                        </InputAdornment>
                      )
                    }}
                  />
                </Grid>
                <Grid item xs={12}>
                  <TextField
                    fullWidth
                    label="Secret Key"
                    value={formData.secret_key}
                    onChange={handleInputChange('secret_key')}
                    type={showSecretKey ? 'text' : 'password'}
                    disabled={loading}
                    InputProps={{
                      endAdornment: (
                        <InputAdornment position="end">
                          <IconButton
                            onClick={() => setShowSecretKey(!showSecretKey)}
                            edge="end"
                          >
                            {showSecretKey ? <VisibilityOff /> : <Visibility />}
                          </IconButton>
                        </InputAdornment>
                      )
                    }}
                  />
                </Grid>
                <Grid item xs={12}>
                  <TextField
                    fullWidth
                    label="Passphrase"
                    value={formData.passphrase}
                    onChange={handleInputChange('passphrase')}
                    type={showPassphrase ? 'text' : 'password'}
                    disabled={loading}
                    InputProps={{
                      endAdornment: (
                        <InputAdornment position="end">
                          <IconButton
                            onClick={() => setShowPassphrase(!showPassphrase)}
                            edge="end"
                          >
                            {showPassphrase ? <VisibilityOff /> : <Visibility />}
                          </IconButton>
                        </InputAdornment>
                      )
                    }}
                  />
                </Grid>
              </Grid>
            </CardContent>
          </Card>
        </Box>
      </DialogContent>

      <DialogActions sx={{ p: 2, gap: 1 }}>
        <Button
          onClick={handleClose}
          disabled={loading}
          variant="outlined"
        >
          Cancelar
        </Button>
        <Button
          onClick={handleSave}
          disabled={loading}
          variant="contained"
          startIcon={loading ? <CircularProgress size={20} /> : <Save />}
        >
          {loading ? 'Salvando...' : 'Salvar'}
        </Button>
      </DialogActions>
    </Dialog>
  );
};

export default Profile;
